<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Acuerdo de transmision · <?= esc($client['nombre_tercero']) ?></title><link rel="stylesheet" href="<?= base_url('assets/css/app.css') ?>"><style>body{margin:0;background:#f4f6f8;color:#17202d}.wrap{max-width:960px;margin:auto;padding:24px 16px 48px}.legal{background:#fff;border:1px solid #dfe3e8;padding:24px;max-height:62vh;overflow:auto}.legal h1{font-size:1.4rem}.legal h2{font-size:1rem;margin-top:20px}.actions{background:#fff;border:1px solid #dfe3e8;padding:20px;margin-top:14px}.signature{width:100%;height:170px;border:1px dashed #667085;touch-action:none}.btn{margin-top:12px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:14px}@media(max-width:760px){.grid{grid-template-columns:1fr}}</style></head><body><main class="wrap"><h1><?= esc($client['nombre_tercero']) ?></h1><p><?= esc($third['nombre']) ?></p><?php if(session('error')): ?><div class="alert alert-error"><?= esc(session('error')) ?></div><?php endif; ?><?php if(session('success')): ?><div class="alert alert-success"><?= esc(session('success')) ?></div><?php endif; ?><?php if($success): ?><div class="alert alert-success"><?= esc($confirmation) ?></div><?php if($agreement['estado']==='vigente'): ?><div class="grid"><form class="actions" method="post" action="<?= base_url('acuerdo-encargado/'.$token.'/incidente') ?>"><?= csrf_field() ?><h2>Notificar incidente</h2><label>Deteccion</label><input type="datetime-local" name="detectado_at" required><label>Conocimiento</label><input type="datetime-local" name="conocimiento_at" required><label>Titulares estimados</label><input type="number" min="0" name="titulares_estimados"><label>Categorias afectadas</label><input name="categorias"><label>Descripcion y contencion inicial</label><textarea name="detalle" required></textarea><button class="btn btn-danger" type="submit">Abrir expediente</button></form><form class="actions" method="post" action="<?= base_url('acuerdo-encargado/'.$token.'/solicitud') ?>"><?= csrf_field() ?><h2>Remitir solicitud de Titular</h2><label>Recibida por el Encargado</label><input type="datetime-local" name="recibida_encargado_at" required><label>Tipo</label><select name="tipo"><option>consulta</option><option>reclamo</option><option>rectificacion</option><option>actualizacion</option><option>revocatoria</option><option>supresion</option></select><label>Nombre</label><input name="titular_nombre" required><label>Documento</label><input name="titular_documento"><label>Correo</label><input type="email" name="titular_email" required><label>Solicitud recibida</label><textarea name="solicitud_texto" required></textarea><button class="btn btn-primary" type="submit">Radicar en Documento 4</button></form></div><?php endif; ?><?php else: ?><div id="legal-instance" class="legal"><?= $agreement['instancia_html'] ?></div><section class="actions"><?php if(empty($agreement['vista_at'])): ?><form method="post" action="<?= base_url('acuerdo-encargado/'.$token.'/visualizacion') ?>"><?= csrf_field() ?><button id="confirm-view" class="btn btn-primary" type="submit" disabled>Confirmar lectura completa</button></form><p class="hint">La confirmacion se habilita al llegar al final del contrato y sus anexos.</p><?php else: ?><form method="post" action="<?= base_url('acuerdo-encargado/'.$token.'/codigo') ?>"><?= csrf_field() ?><button class="btn btn-muted" type="submit">Enviar codigo al representante</button></form><form id="agreement-form" method="post" action="<?= base_url('acuerdo-encargado/'.$token.'/aceptar') ?>"><?= csrf_field() ?><label>Codigo recibido</label><input name="codigo" inputmode="numeric" pattern="[0-9]{6}" maxlength="6" required><label>Firma del representante del Encargado</label><canvas id="signature" class="signature"></canvas><input type="hidden" id="firma_imagen" name="firma_imagen"><button type="button" id="clear-signature" class="btn btn-muted">Limpiar firma</button><label><input type="checkbox" name="acepto" value="1" required> Lei el contrato completo, incluidos sus anexos, y lo suscribo con las facultades verificadas.</label><button class="btn btn-primary" type="submit">Suscribir acuerdo</button></form><?php endif; ?></section><?php endif; ?></main><script>(function(){var legal=document.getElementById('legal-instance'),confirm=document.getElementById('confirm-view');if(legal&&confirm){function end(){confirm.disabled=legal.scrollTop+legal.clientHeight<legal.scrollHeight-8}legal.addEventListener('scroll',end);end()}var c=document.getElementById('signature');if(!c)return;var x=c.getContext('2d'),drawing=false,dirty=false;function size(){var r=c.getBoundingClientRect();c.width=r.width*devicePixelRatio;c.height=r.height*devicePixelRatio;x=c.getContext('2d');x.scale(devicePixelRatio,devicePixelRatio);x.lineWidth=2;x.lineCap='round'}function point(e){var r=c.getBoundingClientRect();return{x:e.clientX-r.left,y:e.clientY-r.top}}c.addEventListener('pointerdown',function(e){drawing=true;dirty=true;var p=point(e);x.beginPath();x.moveTo(p.x,p.y)});c.addEventListener('pointermove',function(e){if(!drawing)return;var p=point(e);x.lineTo(p.x,p.y);x.stroke()});window.addEventListener('pointerup',function(){drawing=false});document.getElementById('clear-signature').addEventListener('click',function(){x.clearRect(0,0,c.width,c.height);dirty=false});document.getElementById('agreement-form').addEventListener('submit',function(){document.getElementById('firma_imagen').value=dirty?c.toDataURL('image/png'):''});size()})();</script></body></html>
